import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.DocumentBuilder;
import org.w3c.dom.Document;
import javax.xml.XMLConstants;
import java.io.InputStream;

public class SecureXMLParser {

    public static Document parseXMLSecurely(InputStream xmlInput) throws Exception {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();

        // Disable DTDs entirely
        dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

        // Disable external entities
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);

        // Disable external DTDs
        dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // Disable XInclude processing
        dbf.setXIncludeAware(false);

        // Disable entity expansion
        dbf.setExpandEntityReferences(false);

        // Enable secure processing
        dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

        DocumentBuilder db = dbf.newDocumentBuilder();

        // Set null EntityResolver to prevent external entity resolution
        db.setEntityResolver((publicId, systemId) -> {
            throw new SecurityException(
                "External entity resolution blocked for security: " + systemId
            );
        });

        return db.parse(xmlInput);
    }

    public static void main(String[] args) {
        try {
            InputStream xmlStream = getXMLInputStream();
            Document doc = parseXMLSecurely(xmlStream);
            System.out.println("XML parsed securely: " + doc.getDocumentElement().getNodeName());
        } catch (Exception e) {
            System.err.println("XML parsing error: " + e.getMessage());
        }
    }
}

