using System;
using System.Xml;
using System.IO;

public class SecureXMLParser
{
    public static XmlDocument ParseXMLSecurely(string xmlInput)
    {
        XmlReaderSettings settings = new XmlReaderSettings();

        // Disable DTD processing entirely
        settings.DtdProcessing = DtdProcessing.Prohibit;

        // Disable external resource resolution
        settings.XmlResolver = null;

        // Set maximum characters to prevent DoS
        settings.MaxCharactersFromEntities = 0;
        settings.MaxCharactersInDocument = 10000000;

        XmlDocument doc = new XmlDocument();
        doc.XmlResolver = null;  // Critical: disable resolver at document level too

        using (StringReader stringReader = new StringReader(xmlInput))
        using (XmlReader reader = XmlReader.Create(stringReader, settings))
        {
            try
            {
                doc.Load(reader);
                return doc;
            }
            catch (XmlException ex)
            {
                throw new SecurityException(
                    $"XML parsing blocked for security: {ex.Message}", ex
                );
            }
        }
    }

    public static void Main()
    {
        string xmlData = "<user><name>John</name></user>";
        try
        {
            XmlDocument doc = ParseXMLSecurely(xmlData);
            Console.WriteLine($"Parsed securely: {doc.DocumentElement.Name}");
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"Error: {ex.Message}");
        }
    }
}

