import javax.xml.parsers.SAXParserFactory;
import javax.xml.parsers.SAXParser;
import org.xml.sax.helpers.DefaultHandler;
import org.xml.sax.InputSource;
import org.xml.sax.SAXException;
import javax.xml.XMLConstants;
import java.io.StringReader;

public class SecureSAXParser {

    public static void parseXMLWithSAX(String xmlInput, DefaultHandler handler) throws Exception {
        SAXParserFactory spf = SAXParserFactory.newInstance();

        // Disable DTDs completely
        spf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

        // Disable external entities
        spf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        spf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);

        // Disable external DTD loading
        spf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // Enable secure processing
        spf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

        // Don't allow namespace processing (optional)
        spf.setNamespaceAware(true);

        SAXParser saxParser = spf.newSAXParser();

        // Set null XMLReader for additional security
        saxParser.getXMLReader().setEntityResolver((publicId, systemId) -> {
            throw new SAXException("External entity resolution blocked: " + systemId);
        });

        InputSource inputSource = new InputSource(new StringReader(xmlInput));
        saxParser.parse(inputSource, handler);
    }

    public static class SecureXMLHandler extends DefaultHandler {
        @Override
        public void startElement(String uri, String localName, String qName, 
                               org.xml.sax.Attributes attributes) throws SAXException {
            System.out.println("Element: " + qName);
        }
    }

    public static void main(String[] args) {
        try {
            String xml = "<user><name>John</name></user>";
            parseXMLWithSAX(xml, new SecureXMLHandler());
        } catch (Exception e) {
            System.err.println("XML parsing error: " + e.getMessage());
        }
    }
}

