import javax.xml.stream.XMLInputFactory;
import javax.xml.stream.XMLStreamReader;
import javax.xml.stream.XMLStreamException;
import javax.xml.XMLConstants;
import java.io.StringReader;

public class SecureStAXParser {

    public static void parseXMLWithStAX(String xmlInput) throws XMLStreamException {
        XMLInputFactory xif = XMLInputFactory.newInstance();

        // Disable DTD processing
        xif.setProperty(XMLInputFactory.SUPPORT_DTD, false);

        // Disable external entity processing
        xif.setProperty(XMLInputFactory.IS_SUPPORTING_EXTERNAL_ENTITIES, false);

        // Enable secure processing
        xif.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        xif.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

        XMLStreamReader reader = xif.createXMLStreamReader(new StringReader(xmlInput));

        try {
            while (reader.hasNext()) {
                int event = reader.next();

                switch (event) {
                    case XMLStreamReader.START_ELEMENT:
                        System.out.println("Start Element: " + reader.getLocalName());
                        break;
                    case XMLStreamReader.CHARACTERS:
                        if (!reader.isWhiteSpace()) {
                            System.out.println("Text: " + reader.getText());
                        }
                        break;
                    case XMLStreamReader.END_ELEMENT:
                        System.out.println("End Element: " + reader.getLocalName());
                        break;
                }
            }
        } finally {
            reader.close();
        }
    }

    public static void main(String[] args) {
        try {
            String xml = "<user><name>John</name></user>";
            parseXMLWithStAX(xml);
        } catch (XMLStreamException e) {
            System.err.println("XML parsing error: " + e.getMessage());
        }
    }
}

