import javax.xml.XMLConstants;
import javax.xml.transform.stream.StreamSource;
import javax.xml.validation.Schema;
import javax.xml.validation.SchemaFactory;
import javax.xml.validation.Validator;
import org.xml.sax.SAXException;
import java.io.StringReader;
import java.io.File;

public class XMLSchemaValidator {

    private static final String SCHEMA_PATH = "/path/to/schema.xsd";

    public static boolean validateXMLAgainstSchema(String xmlInput) {
        try {
            // Create schema factory
            SchemaFactory schemaFactory = SchemaFactory.newInstance(
                XMLConstants.W3C_XML_SCHEMA_NS_URI
            );

            // Disable external entity resolution in schema factory
            schemaFactory.setProperty(
                XMLConstants.ACCESS_EXTERNAL_DTD, ""
            );
            schemaFactory.setProperty(
                XMLConstants.ACCESS_EXTERNAL_SCHEMA, ""
            );

            // Load and compile schema
            Schema schema = schemaFactory.newSchema(new File(SCHEMA_PATH));

            // Create validator
            Validator validator = schema.newValidator();

            // Disable external entities in validator
            validator.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            validator.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            // Validate XML input
            validator.validate(new StreamSource(new StringReader(xmlInput)));

            System.out.println("XML validation successful");
            return true;

        } catch (SAXException e) {
            System.err.println("XML validation failed: Schema violation");
            return false;
        } catch (Exception e) {
            System.err.println("XML validation error: Invalid input");
            return false;
        }
    }

    public static String sanitizeXMLInput(String xmlInput) {
        // Check for DOCTYPE declaration
        if (xmlInput.contains("<!DOCTYPE") || 
            xmlInput.contains("<!ENTITY") ||
            xmlInput.toLowerCase().contains("<!doctype")) {
            throw new SecurityException(
                "DOCTYPE declarations are not permitted"
            );
        }

        // Check for suspicious patterns
        if (xmlInput.contains("SYSTEM") || xmlInput.contains("PUBLIC")) {
            throw new SecurityException(
                "External entity references are not permitted"
            );
        }

        // Limit XML size to prevent DoS
        if (xmlInput.length() > 1_000_000) {  // 1MB limit
            throw new SecurityException(
                "XML input exceeds maximum allowed size"
            );
        }

        return xmlInput;
    }

    public static void main(String[] args) {
        String xmlInput = "<user><name>John</name><email>john@example.com</email></user>";

        try {
            // First sanitize input
            String sanitized = sanitizeXMLInput(xmlInput);

            // Then validate against schema
            if (validateXMLAgainstSchema(sanitized)) {
                System.out.println("XML is safe to process");
            } else {
                System.out.println("XML validation failed");
            }
        } catch (SecurityException e) {
            System.err.println("Security violation: " + e.getMessage());
        }
    }
}

