from lxml import etree
from defusedxml.lxml import fromstring
import re

class XMLValidator:

    def __init__(self, schema_path):
        """Initialize with XSD schema file path."""
        with open(schema_path, 'r') as schema_file:
            schema_root = etree.XML(schema_file.read())
            self.schema = etree.XMLSchema(schema_root)

    def sanitize_xml_input(self, xml_input):
        """Sanitize XML input before processing."""
        # Check for DOCTYPE declarations
        if re.search(r'<!DOCTYPE', xml_input, re.IGNORECASE):
            raise SecurityException("DOCTYPE declarations are not permitted")

        # Check for ENTITY declarations
        if re.search(r'<!ENTITY', xml_input, re.IGNORECASE):
            raise SecurityException("ENTITY declarations are not permitted")

        # Check for SYSTEM/PUBLIC keywords
        if 'SYSTEM' in xml_input or 'PUBLIC' in xml_input:
            raise SecurityException("External references are not permitted")

        # Limit size to prevent DoS
        if len(xml_input) > 1_000_000:  # 1MB
            raise SecurityException("XML input exceeds maximum size")

        return xml_input

    def validate(self, xml_input):
        """Validate XML against schema."""
        try:
            # First sanitize
            sanitized = self.sanitize_xml_input(xml_input)

            # Parse with defusedxml
            xml_doc = fromstring(sanitized.encode('utf-8'))

            # Validate against schema
            if not self.schema.validate(xml_doc):
                errors = self.schema.error_log
                raise ValidationException(
                    f"Schema validation failed: {errors}"
                )

            return xml_doc

        except etree.XMLSyntaxError as e:
            raise ValidationException(f"XML syntax error: Invalid format")
        except Exception as e:
            raise ValidationException(f"Validation error: {str(e)}")

class SecurityException(Exception):
    pass

class ValidationException(Exception):
    pass

# Example usage
if __name__ == "__main__":
    validator = XMLValidator('/path/to/schema.xsd')

    xml_input = '<user><name>John</name><email>john@example.com</email></user>'

    try:
        validated_doc = validator.validate(xml_input)
        print("XML is valid and safe to process")
    except (SecurityException, ValidationException) as e:
        print(f"Validation error: {e}")

from flask import Flask, request, jsonify
from functools import wraps
import logging
import re

app = Flask(__name__)

# Configure logging
logging.basicConfig(
    level=logging.WARNING,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger(__name__)

def xxe_protection_middleware(f):
    """Middleware to detect and block XXE attacks."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Check Content-Type
        content_type = request.content_type or ''

        if 'xml' in content_type.lower():
            try:
                body = request.get_data(as_text=True)

                # Check for XXE indicators
                xxe_patterns = [
                    r'<!DOCTYPE',
                    r'<!ENTITY',
                    r'SYSTEM\s*["\']',
                    r'PUBLIC\s*["\']',
                    r'file://',
                    r'http://169\.254\.169\.254',  # AWS metadata
                    r'http://metadata\.google\.internal',  # GCP metadata
                ]

                for pattern in xxe_patterns:
                    if re.search(pattern, body, re.IGNORECASE):
                        logger.warning(
                            f"XXE attack detected from {request.remote_addr} "
                            f"- Pattern: {pattern}"
                        )
                        return jsonify({
                            'error': 'Invalid request',
                            'message': 'Request blocked for security reasons'
                        }), 403

                # Check body size
                if len(body) > 1_000_000:  # 1MB limit
                    logger.warning(
                        f"Oversized XML from {request.remote_addr} "
                        f"- Size: {len(body)} bytes"
                    )
                    return jsonify({
                        'error': 'Payload too large',
                        'message': 'XML exceeds maximum size'
                    }), 413

            except Exception as e:
                logger.error(f"XXE middleware error: {str(e)}")
                return jsonify({
                    'error': 'Processing error'
                }), 500

        return f(*args, **kwargs)

    return decorated_function

@app.route('/api/xml', methods=['POST'])
@xxe_protection_middleware
def process_xml():
    """Process XML endpoint with XXE protection."""
    # Additional secure XML processing here
    return jsonify({'status': 'success'})

if __name__ == '__main__':
    app.run(debug=False)

const express = require('express');
const helmet = require('helmet');

const app = express();

// Apply security headers
app.use(helmet());

// XXE Protection Middleware
function xxeProtectionMiddleware(req, res, next) {
  const contentType = req.get('Content-Type') || '';

  if (contentType.toLowerCase().includes('xml')) {
    let body = '';

    req.on('data', chunk => {
      body += chunk.toString();

      // Size limit check
      if (body.length > 1000000) {  // 1MB
        req.removeAllListeners('data');
        res.status(413).json({
          error: 'Payload too large',
          message: 'XML exceeds maximum size'
        });
        return;
      }
    });

    req.on('end', () => {
      // XXE pattern detection
      const xxePatterns = [
        /<!DOCTYPE/i,
        /<!ENTITY/i,
        /SYSTEM\s*["']/i,
        /PUBLIC\s*["']/i,
        /file:\/\//i,
        /http:\/\/169\.254\.169\.254/i,  // AWS metadata
        /http:\/\/metadata/i
      ];

      for (const pattern of xxePatterns) {
        if (pattern.test(body)) {
          console.warn(
            `XXE attack detected from ${req.ip} - ` +
            `Pattern: ${pattern.source}`
          );

          return res.status(403).json({
            error: 'Invalid request',
            message: 'Request blocked for security reasons'
          });
        }
      }

      req.body = body;
      next();
    });
  } else {
    next();
  }
}

app.use(xxeProtectionMiddleware);

app.post('/api/xml', (req, res) => {
  // Process XML securely here
  res.json({ status: 'success' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
